// src/components/ServicesHero.jsx
import React from 'react';
import ServicesDiamond from '../components/ServicesDiamond';


export default function ServicesHero() {
  const diamonds = [
    {
      id: 'diamond1',
      src: '/images/Frame-411.png',
      alt: 'Analytics Icon',
      title: 'Analytics Service',
    },
    {
      id: 'diamond2',
      src: '/images/Frame-488.png',
      alt: 'SEO Icon',
      title: 'SEO Service',
    },
    {
      id: 'diamond3',
      src: '/images/Frame-412.png',
      alt: 'Development Icon',
      title: 'Development Service',
    },
  ];

  return (
    <div className="page-wrapper">
      <div className="hero-inner">
        <div className='services-section'>
        <div className="hero-diamonds">
          {diamonds.map(({ id, src, alt, title }) => (
            <ServicesDiamond
              key={id}
              className={`diamond ${id}`}
              src={src}
              alt={alt}
              title={title}
            />
          ))}
        </div>
        </div>
      </div>
    </div>
  );
}
